import{_ as a,c as t,o as e,a2 as r}from"./chunks/framework.BX_emVE_.js";const N=JSON.parse('{"title":"NapCatQQ","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/guide/getting-started.md","filePath":"zh-CN/guide/getting-started.md","lastUpdated":1722256565000}'),o={name:"zh-CN/guide/getting-started.md"},p=r('<h1 id="napcatqq" tabindex="-1">NapCatQQ <a class="header-anchor" href="#napcatqq" aria-label="Permalink to &quot;NapCatQQ&quot;">​</a></h1><p>NapCatQQ 是基于 PC NTQQ 客户端本体实现的 QQ Bot 框架，稳定安全，快速部署。</p><h2 id="napcatqq-的优势" tabindex="-1">NapCatQQ 的优势 <a class="header-anchor" href="#napcatqq-的优势" aria-label="Permalink to &quot;NapCatQQ 的优势&quot;">​</a></h2><ul><li><p>不需要图形环境，Linux表现优异，与现有Hook框架有着本质区别，在性能与内存占用方面远远优于基于Hook的框架。</p></li><li><p>配置简单，支持浏览器远程进入进行配置，简单轻松即可完成配置。</p></li><li><p>NTQQ功能适配快速，更新持续跟进QQ最新版。</p></li></ul><h2 id="启动前需要了解的三两事-你给我好好读三遍" tabindex="-1">启动前需要了解的三两事 (！你给我好好读三遍) <a class="header-anchor" href="#启动前需要了解的三两事-你给我好好读三遍" aria-label="Permalink to &quot;启动前需要了解的三两事 (！你给我好好读三遍)&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><ul><li><p>NapCat 是基于 PC NTQQ 客户端本体实现的 QQ Bot 框架，所以说需要提前安装好和 <strong>NapCatQQ 对应的 QQ 版本</strong>才能运行 NapCat。</p></li><li><p>NapCat 在线时，你不能使用 PC QQ 客户端实现人机合一，但是可以选择同步登录移动客户端，如果想要在 PC 上人机合一请使用 <a href="https://github.com/LLOneBot/LLOneBot" target="_blank" rel="noreferrer">LLOneBot</a></p></li><li><p>NapCat 不同于协议实现，是基于 QQ 客户端，QQ 客户端上干不了的事，NapCat &gt;_&lt; 当然也是不行的!</p></li></ul></div><h2 id="安装-qq" tabindex="-1">安装 QQ <a class="header-anchor" href="#安装-qq" aria-label="Permalink to &quot;安装 QQ&quot;">​</a></h2><p>直接到QQ官网安装最新LinuxQQ即可</p><h2 id="下载-napcatqq" tabindex="-1">下载 NapCatQQ <a class="header-anchor" href="#下载-napcatqq" aria-label="Permalink to &quot;下载 NapCatQQ&quot;">​</a></h2><p>下载地址: <a href="https://github.com/NapNeko/NapCatQQ/releases" target="_blank" rel="noreferrer">https://github.com/NapNeko/NapCatQQ/releases</a></p><p>更多版本更新日志请查看<a href="./version">版本更新记录</a>。</p><h2 id="配置napcatqq" tabindex="-1">配置NapCatQQ <a class="header-anchor" href="#配置napcatqq" aria-label="Permalink to &quot;配置NapCatQQ&quot;">​</a></h2><p>为了避免二次启动，可以事先配置好 NapCat 的基础设置，见 <a href="./config">配置 NapCat</a>。</p><h2 id="启动napcatqq" tabindex="-1">启动NapCatQQ <a class="header-anchor" href="#启动napcatqq" aria-label="Permalink to &quot;启动NapCatQQ&quot;">​</a></h2><details class="details custom-block"><summary>Win 64系统手动配置</summary><p>Way5仅支持WinX64 <a href="/zh-CN/guide/BootWay05">前往了解BootWay5手动配置方案</a></p></details><details class="details custom-block"><summary>Linux一键脚本</summary><p><code>curl -o napcat.sh https://fastly.jsdelivr.net/gh/NapNeko/NapCat-Installer@master/script/install.sh &amp;&amp; sudo bash napcat.sh</code></p></details><details class="details custom-block"><summary><a href="https://github.com/NapNeko/NapCat-Docker" target="_blank" rel="noreferrer">Linux Docker</a></summary><p><a href="https://github.com/NapNeko/NapCat-Docker" target="_blank" rel="noreferrer">点击前往</a></p></details><details class="details custom-block"><summary>不想使用方便的方式? 想手动配置</summary><p>Way5仅支持WinX64 <a href="/zh-CN/guide/BootWay05">前往了解BootWay5手动配置方案</a> Way3支持任意系统 <a href="/zh-CN/guide/BootWay03">前往了解BootWay3手动配置方案</a></p></details><h3 id="启动之后" tabindex="-1">启动之后 <a class="header-anchor" href="#启动之后" aria-label="Permalink to &quot;启动之后&quot;">​</a></h3><p>恭喜你，如果看到这里，你已经成功启动了 NapCat，可以尝试阅读下面的进阶说明！</p><p><a href="/zh-CN/guide/config">如何进行 NapCat 的基础设置</a></p><p><a href="/zh-CN/guide/faq">如何配置 NapCat 的语音发送</a> 参考 <code>语音、视频发送失败</code> 发生失败条目</p><p><a href="/zh-CN/guide/faq">遇到 NapCat 崩溃问题如何解决</a></p>',23),i=[p];function s(l,n,h,c,d,u){return e(),t("div",null,i)}const m=a(o,[["render",s]]);export{N as __pageData,m as default};
